function DocUploadRow({
  label,
  path,
  url,
  onSet,
  onPick,
}: {
  label: string;
  path: string;
  url: string | null;
  onSet: (path: string) => void;
  onPick: (file?: File | null) => void;
}) {
  return (
    <div className="rounded-2xl border p-3">
      <div className="text-sm font-semibold text-black">{label}</div>
      <div className="mt-1 text-xs text-gray-500 break-all">{path || "Not uploaded"}</div>
      <div className="mt-3 flex items-center gap-2">
        {url ? (
          <a
            href={url}
            target="_blank"
            rel="noreferrer"
            className="px-3 py-2 rounded-xl border bg-white text-sm text-blue-600"
          >
            View
          </a>
        ) : null}
        <label className="px-3 py-2 rounded-xl bg-[#FFDA03] text-black text-sm font-semibold cursor-pointer">
          Upload
          <input
            type="file"
            className="hidden"
            accept="image/*,application/pdf"
            onChange={(e) => onPick(e.target.files?.[0])}
          />
        </label>
        <button
          type="button"
          onClick={() => onSet("")}
          className="px-3 py-2 rounded-xl border bg-white text-black text-sm"
        >
          Clear
        </button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";

type SplashScreenProps = {
  onFinish?: () => void;
  fadingOut?: boolean;
};

export default function SplashScreen({
  onFinish,
  fadingOut = false,
}: SplashScreenProps) {
  const [bgBlack, setBgBlack] = useState(false);
  const [progress, setProgress] = useState(0);
  const finishRef = useRef(onFinish);

  useEffect(() => {
    finishRef.current = onFinish;
  }, [onFinish]);

  useEffect(() => {
    const started = Date.now();
    const totalMs = 2300;
    const bgTimer = setTimeout(() => setBgBlack(true), 1200);

    const interval = setInterval(() => {
      const elapsed = Date.now() - started;
      const pct = Math.max(0, Math.min(100, (elapsed / totalMs) * 100));
      setProgress(pct);
    }, 30);

    const finishTimer = setTimeout(() => finishRef.current?.(), totalMs);

    return () => {
      clearTimeout(bgTimer);
      clearTimeout(finishTimer);
      clearInterval(interval);
    };
  }, []);

  return (
    <div
      className={`fixed inset-0 z-50 flex flex-col items-center justify-center transition-all duration-500 ${
        bgBlack ? "bg-black" : "bg-white"
      } ${fadingOut ? "opacity-0 pointer-events-none" : "opacity-100"}`}
    >
      <div className="mb-7 relative h-40 w-40 md:h-48 md:w-48 overflow-hidden">
        <img
          src="/Logo.png"
          alt="Faragon Logo Base"
          className="absolute inset-0 h-full w-full object-contain opacity-20"
        />
        <div
          className="absolute inset-0 overflow-hidden transition-all duration-75"
          style={{ clipPath: `inset(${100 - progress}% 0 0 0)` }}
        >
          <img
            src="/Logo.png"
            alt="Faragon Logo"
            className="h-full w-full object-contain"
          />
        </div>
      </div>

      <h1
        className="text-center text-sm md:text-base uppercase tracking-[0.28em] font-FaragonFont px-4"
        style={{
          backgroundImage: bgBlack
            ? `linear-gradient(to right, #ffffff ${progress}%, rgba(255,255,255,0.25) ${progress}%)`
            : `linear-gradient(to right, #b91c1c ${progress}%, rgba(185,28,28,0.30) ${progress}%)`,
          WebkitBackgroundClip: "text",
          color: "transparent",
          transition: "background-image 120ms linear",
        }}
      >
        FARAGON SECURITY AGENCY INC.
      </h1>

      <style jsx>{`
        :global(body) {
          overflow: hidden;
        }
      `}</style>
    </div>
  );
}

