            </div>
          </div>

          <div className="px-6 pb-6 flex items-center justify-between gap-2">
            <button onClick={clearFilters} className="px-4 py-2 rounded-xl border bg-white">
              Clear
            </button>
            <button
              onClick={() => setFiltersOpen(false)}
