                    <td className="px-4 py-3">{safeText(r.paraphernalia_inventory?.items)}</td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <button
                          type="button"
                          onClick={() => openEdit("restock", r)}
                          className="animated-btn inline-flex items-center gap-1 rounded-lg border bg-white px-2 py-1 text-xs hover:bg-white"
                        >
                          <Pencil className="w-3.5 h-3.5" />
                          Edit
                        </button>
                        <button
                          type="button"
                          onClick={() => openDelete("restock", r.id_restock, r.item ?? "restock row")}
                          className="animated-btn inline-flex items-center gap-1 rounded-lg border border-red-200 text-red-600 px-2 py-1 text-xs hover:bg-red-50"
                        >
                          <Trash2 className="w-3.5 h-3.5" />
                          Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={6} className="px-4 py-8 text-center text-gray-400">No restock rows.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {createOpen ? (
        <div className="fixed inset-0 z-[80] bg-black/40 flex items-center justify-center p-4">
          <div className="w-full max-w-4xl glass-panel rounded-2xl shadow-2xl max-h-[90vh] overflow-y-auto animate-scale-in">
            <div className="px-5 py-4 border-b sticky top-0 bg-white">
              <div className="text-base font-semibold text-black">Add Paraphernalia Data</div>
              <div className="text-sm text-gray-500">Segmented form for Paraphernalia Items, Inventory Stock Snapshot, and Restock History.</div>
            </div>

            <form onSubmit={handleCreateSubmit} className="px-5 py-4 space-y-5">
              <div className="glass-panel rounded-2xl border-none p-4 space-y-3">
                <div className="text-sm font-semibold text-black">Paraphernalia Items</div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Name *</span>
                    <input
                      value={form.names}
                      onChange={(e) => setForm((prev) => ({ ...prev, names: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="Enter name"
                      required
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Item *</span>
                    <input
                      value={form.items}
                      onChange={(e) => setForm((prev) => ({ ...prev, items: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="Enter item"
                      required
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Quantity</span>
                    <input
                      type="number"
                      value={form.quantity}
                      onChange={(e) => setForm((prev) => ({ ...prev, quantity: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="0"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Unit Price</span>
                    <input
                      type="number"
                      step="0.01"
                      value={form.price}
                      onChange={(e) => setForm((prev) => ({ ...prev, price: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="0.00"
                    />
                  </label>
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Date</span>
                    <input
                      type="date"
                      value={form.date}
                      onChange={(e) => setForm((prev) => ({ ...prev, date: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                    />
                  </label>
                </div>
              </div>

              <div className="glass-panel rounded-2xl border-none p-4 space-y-3">
                <div className="flex items-center justify-between gap-2">
                  <div className="text-sm font-semibold text-black">Inventory Stock Snapshot</div>
                  <label className="flex items-center gap-2 text-xs text-gray-600">
                    <input
                      type="checkbox"
                      checked={form.createInventory}
                      onChange={(e) => setForm((prev) => ({ ...prev, createInventory: e.target.checked }))}
                    />
                    Include this section
                  </label>
                </div>
                <div className={`grid grid-cols-1 md:grid-cols-2 gap-4 ${form.createInventory ? "" : "opacity-50 pointer-events-none"}`}>
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Inventory Item</span>
                    <input
                      value={form.inventoryItems}
                      onChange={(e) => setForm((prev) => ({ ...prev, inventoryItems: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="Defaults to Paraphernalia Item"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Stock Balance</span>
                    <input
                      type="number"
                      value={form.stockBalance}
                      onChange={(e) => setForm((prev) => ({ ...prev, stockBalance: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="0"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Stock In</span>
                    <input
                      type="number"
                      value={form.stockIn}
                      onChange={(e) => setForm((prev) => ({ ...prev, stockIn: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="0"
                    />
                  </label>
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Stock Out</span>
                    <input
                      type="number"
                      value={form.stockOut}
                      onChange={(e) => setForm((prev) => ({ ...prev, stockOut: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="0"
                    />
                  </label>
                </div>
              </div>

              <div className="glass-panel rounded-2xl border-none p-4 space-y-3">
                <div className="flex items-center justify-between gap-2">
                  <div className="text-sm font-semibold text-black">Restock History</div>
                  <label className="flex items-center gap-2 text-xs text-gray-600">
                    <input
                      type="checkbox"
                      checked={form.createRestock}
                      onChange={(e) => setForm((prev) => ({ ...prev, createRestock: e.target.checked }))}
                    />
                    Include this section
                  </label>
                </div>
                <div className={`grid grid-cols-1 md:grid-cols-2 gap-4 ${form.createRestock ? "" : "opacity-50 pointer-events-none"}`}>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Date</span>
                    <input
                      type="date"
                      value={form.restockDate}
                      onChange={(e) => setForm((prev) => ({ ...prev, restockDate: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Status</span>
                    <input
                      value={form.restockStatus}
                      onChange={(e) => setForm((prev) => ({ ...prev, restockStatus: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="e.g. Restocked"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Item</span>
                    <input
                      value={form.restockItem}
                      onChange={(e) => setForm((prev) => ({ ...prev, restockItem: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="Defaults to Paraphernalia Item"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Quantity</span>
                    <input
                      value={form.restockQuantity}
                      onChange={(e) => setForm((prev) => ({ ...prev, restockQuantity: e.target.value }))}
                      className="w-full px-3 py-2 border rounded-xl text-black focus:outline-none focus:ring-2 focus:ring-yellow-300"
                      placeholder="e.g. 10"
                    />
                  </label>
                </div>
              </div>

              {createError ? (
                <div className="rounded-xl border bg-red-50 px-3 py-2 text-sm text-red-700">{createError}</div>
              ) : null}

              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setCreateOpen(false)}
                  disabled={createBusy}
                  className="animated-btn px-4 py-2 rounded-xl border bg-white text-sm text-black hover:bg-white disabled:opacity-60"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={createBusy}
                  className="animated-btn px-4 py-2 rounded-xl bg-[#FFDA03] text-black text-sm font-medium hover:brightness-95 disabled:opacity-60"
                >
                  {createBusy ? "Saving..." : "Save All Connected Data"}
                </button>
              </div>
            </form>
          </div>
        </div>
      ) : null}

      {editState ? (
        <div className="fixed inset-0 z-[85] bg-black/40 flex items-center justify-center p-4">
          <div className="w-full max-w-2xl glass-panel animate-scale-in rounded-2xl shadow-2xl">
            <div className="px-5 py-4 border-b">
              <div className="text-base font-semibold text-black">Edit {editState.section === "paraphernalia" ? "Paraphernalia Item" : editState.section === "inventory" ? "Inventory Snapshot" : "Restock History"}</div>
            </div>

            <form onSubmit={saveEdit} className="px-5 py-4 space-y-4">
              {editState.section === "paraphernalia" ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Name</span>
                    <input
                      value={editState.row.names ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "paraphernalia"
                            ? { ...prev, row: { ...prev.row, names: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Item</span>
                    <input
                      value={editState.row.items ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "paraphernalia"
                            ? { ...prev, row: { ...prev.row, items: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Quantity</span>
                    <input
                      type="number"
                      value={editState.row.quantity ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "paraphernalia"
                            ? { ...prev, row: { ...prev.row, quantity: toNumberOrNull(e.target.value) } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Unit Price</span>
                    <input
                      type="number"
                      value={editState.row.price ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "paraphernalia"
                            ? { ...prev, row: { ...prev.row, price: toNumberOrNull(e.target.value) } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Date</span>
                    <input
                      value={editState.row.date ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "paraphernalia"
                            ? { ...prev, row: { ...prev.row, date: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                </div>
              ) : null}

              {editState.section === "inventory" ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Item</span>
                    <input
                      value={editState.row.items ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "inventory"
                            ? { ...prev, row: { ...prev.row, items: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Stock Balance</span>
                    <input
                      type="number"
                      value={editState.row.stock_balance ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "inventory"
                            ? { ...prev, row: { ...prev.row, stock_balance: toNumberOrNull(e.target.value) } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Stock In</span>
                    <input
                      type="number"
                      value={editState.row.stock_in ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "inventory"
                            ? { ...prev, row: { ...prev.row, stock_in: toNumberOrNull(e.target.value) } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm md:col-span-2">
                    <span className="text-gray-700">Stock Out</span>
                    <input
                      type="number"
                      value={editState.row.stock_out ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "inventory"
                            ? { ...prev, row: { ...prev.row, stock_out: toNumberOrNull(e.target.value) } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                </div>
              ) : null}

              {editState.section === "restock" ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Date</span>
                    <input
                      value={editState.row.date ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "restock"
                            ? { ...prev, row: { ...prev.row, date: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Status</span>
                    <input
                      value={editState.row.status ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "restock"
                            ? { ...prev, row: { ...prev.row, status: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Item</span>
                    <input
                      value={editState.row.item ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "restock"
                            ? { ...prev, row: { ...prev.row, item: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                  <label className="space-y-1 text-sm">
                    <span className="text-gray-700">Quantity</span>
                    <input
                      value={editState.row.quanitity ?? ""}
                      onChange={(e) =>
                        setEditState((prev) =>
                          prev && prev.section === "restock"
                            ? { ...prev, row: { ...prev.row, quanitity: e.target.value } }
                            : prev
                        )
                      }
                      className="w-full px-3 py-2 border rounded-xl"
                    />
                  </label>
                </div>
              ) : null}

              {editError ? <div className="rounded-xl border bg-red-50 px-3 py-2 text-sm text-red-700">{editError}</div> : null}

              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setEditState(null)}
                  disabled={editBusy}
                  className="animated-btn px-4 py-2 rounded-xl border bg-white text-sm hover:bg-white disabled:opacity-60"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={editBusy}
                  className="animated-btn px-4 py-2 rounded-xl bg-[#FFDA03] text-black text-sm font-medium hover:brightness-95 disabled:opacity-60"
                >
                  {editBusy ? "Saving..." : "Save Changes"}
                </button>
              </div>
            </form>
          </div>
        </div>
      ) : null}

      {deleteState ? (
        <div className="fixed inset-0 z-[90] bg-black/40 flex items-center justify-center p-4">
          <div className="w-full max-w-md glass-panel animate-scale-in rounded-2xl shadow-2xl">
            <div className="px-5 py-4 border-b">
              <div className="text-base font-semibold text-black">Confirm Delete</div>
              <div className="mt-1 text-sm text-gray-600">Delete this {deleteState.section} row: {safeText(deleteState.label)}?</div>
            </div>
            <div className="px-5 py-4 space-y-3">
              {deleteError ? <div className="rounded-xl border bg-red-50 px-3 py-2 text-sm text-red-700">{deleteError}</div> : null}
              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setDeleteState(null)}
                  disabled={deleteBusy}
                  className="animated-btn px-4 py-2 rounded-xl border bg-white text-sm hover:bg-white disabled:opacity-60"
                >
                  Cancel
                </button>
                <button
                  type="button"
                  onClick={() => void confirmDelete()}
                  disabled={deleteBusy}
                  className="animated-btn px-4 py-2 rounded-xl bg-red-600 text-white text-sm font-medium hover:bg-red-700 disabled:opacity-60"
                >
                  {deleteBusy ? "Deleting..." : "Delete"}
                </button>
              </div>
            </div>
          </div>
        </div>
      ) : null}

      {showExportPopup && (
        <div className="fixed inset-0 flex items-center justify-center bg-black/40 z-50">
          <div className="bg-white w-[750px] rounded-2xl shadow-xl overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b">
              <h2 className="text-2xl font-semibold">Export Paraphernalia</h2>
              <button
                onClick={() => setShowExportPopup(false)}
                className="border px-4 py-2 rounded-xl hover:bg-gray-100"
              >
                Close
              </button>
            </div>
            <div className="p-6">
              <p className="text-gray-600 mb-6">Choose the format you want to export.</p>
              <div className="flex gap-4">
                <button
                  onClick={exportParaphernaliaXlsx}
                  className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-medium text-black hover:bg-white"
                >
                  <FileDown className="w-4 h-4" />
                  Export XLSX
                </button>
                <button
                  onClick={exportParaphernaliaCsv}
                  className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-medium text-black hover:bg-white"
                >
                  <FileDown className="w-4 h-4" />
                  Export CSV
                </button>
                <button
                  onClick={exportParaphernaliaPdf}
                  className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-medium text-black hover:bg-white"
                >
                  <FileText className="w-4 h-4" />
                  Export PDF
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showTemplatePopup && (
        <div className="fixed inset-0 flex items-center justify-center bg-black/40 z-50">
          <div className="bg-white w-[750px] rounded-2xl shadow-xl overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4 border-b">
              <h2 className="text-2xl font-semibold">Download Templates</h2>
              <button
                onClick={() => setShowTemplatePopup(false)}
                className="border px-4 py-2 rounded-xl hover:bg-gray-100"
              >
                Close
              </button>
            </div>
            <div className="p-6">
              <p className="text-gray-600 mb-6">Download a template file for importing paraphernalia data.</p>
              <div className="flex gap-4">
                <button
                  onClick={() => downloadTemplate("xlsx")}
                  className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-medium text-black hover:bg-white"
                >
                  <Download className="w-4 h-4" />
                  Template XLSX
                </button>
                <button
                  onClick={() => downloadTemplate("csv")}
                  className="inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-medium text-black hover:bg-white"
                >
                  <Download className="w-4 h-4" />
                  Template CSV
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <SpreadsheetImportModal
        open={importModalOpen}
        onClose={() => setImportModalOpen(false)}
        title="Import Paraphernalia"
        description="Upload an Excel (.xlsx/.xls) or CSV (.csv) file with paraphernalia data."
        allowTemplateDownloads={canDownloadParaphernaliaTemplate}
        templateFileName="paraphernalia_import_template"
        templateSampleData={{
          names: "Sample Name",
          items: "Sample Item",
          quantity: 10,
          price: 50,
          date: "2026-03-01",
        }}
        previewColumns={["Name/Item"]}
        parseRow={parseParaphernaliaImportRow}
        onImport={handleParaphernaliaImport}
      />

      <ImportSummaryModal
        open={importSummaryOpen}
        summary={importSummary}
        title="Paraphernalia Import Summary"
        onClose={() => setImportSummaryOpen(false)}
      />
    </div>
  );
}

"use client";

import React, { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../Client/SupabaseClients";
import { Pencil, LayoutGrid, Table, SlidersHorizontal, Search, FileDown, FileText, Trash2 } from "lucide-react";
import { useAuthRole } from "../../Client/useRbac";
import EmployeeEditorModal from "../../Components/EmployeeEditorModal";
import LoadingCircle from "../../Components/LoadingCircle";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

type Applicant = {
  applicant_id: string;
  created_at: string;
  first_name: string | null;
  middle_name: string | null;
  last_name: string | null;
  client_position: string | null;
  date_hired_fsai: string | null;
  detachment: string | null;
  status: string | null;
  gender: string | null;
  birth_date: string | null;
  age: number | null;
  client_contact_num: string | null;
  client_email: string | null;
  profile_image_path: string | null;
  is_archived: boolean | null;
  is_trashed?: boolean | null;
};

type LicensureRow = {
  applicant_id: string;
  driver_expiration: string | null;
  security_expiration: string | null;
  insurance_expiration: string | null;
};

const BUCKETS = {
  profile: "applicants",
};

function getFullName(a: Applicant) {
  const parts = [a.first_name, a.middle_name, a.last_name].filter(Boolean);
  return parts.length ? parts.join(" ") : "(No name)";
}

function getProfileUrl(profilePath: string | null) {
  if (!profilePath) return null;
  const { data } = supabase.storage.from(BUCKETS.profile).getPublicUrl(profilePath);
  return data.publicUrl || null;
}

function shortCode(id: string) {
  return `EMP-${id.slice(0, 2).toUpperCase()}-${id.slice(2, 5).toUpperCase()}`;
}

function normalizeStatus(input: string | null) {
  const v = (input ?? "").trim().toUpperCase();
  if (!v) return "ACTIVE";
  if (v === "ACTIVE" || v === "INACTIVE" || v === "REASSIGN" || v === "RETIRED" || v === "RESIGNED") return v;
  return "ACTIVE";
}

function startOfDay(d: Date) {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate(), 0, 0, 0, 0);
}

function addYearsClamped(base: Date, years: number) {
  const y = base.getFullYear() + years;
  const m = base.getMonth();
  const day = base.getDate();
  const lastDay = new Date(y, m + 1, 0).getDate();
  return new Date(y, m, Math.min(day, lastDay), 0, 0, 0, 0);
}

function addMonthsClamped(base: Date, months: number) {
  const y = base.getFullYear();
  const m = base.getMonth() + months;
  const day = base.getDate();
  const first = new Date(y, m, 1, 0, 0, 0, 0);
  const lastDay = new Date(first.getFullYear(), first.getMonth() + 1, 0).getDate();
  return new Date(first.getFullYear(), first.getMonth(), Math.min(day, lastDay), 0, 0, 0, 0);
}

function diffYearsMonthsDays(from: Date, to: Date) {
  const start = startOfDay(from);
  const end = startOfDay(to);
  if (end.getTime() < start.getTime()) return { years: 0, months: 0, days: 0 };

  let years = end.getFullYear() - start.getFullYear();
  let cursor = addYearsClamped(start, years);
  if (cursor.getTime() > end.getTime()) {
    years -= 1;
    cursor = addYearsClamped(start, years);
  }

  let months = (end.getFullYear() - cursor.getFullYear()) * 12 + (end.getMonth() - cursor.getMonth());
  let cursor2 = addMonthsClamped(cursor, months);
  if (cursor2.getTime() > end.getTime()) {
    months -= 1;
    cursor2 = addMonthsClamped(cursor, months);
  }

  const msPerDay = 24 * 60 * 60 * 1000;
  const days = Math.max(0, Math.round((end.getTime() - cursor2.getTime()) / msPerDay));
  return { years: Math.max(0, years), months: Math.max(0, months), days };
}

function serviceYearsExact(fromIso: string | null, now = new Date()) {
  if (!fromIso) return null;
  const d = new Date(fromIso);
  if (Number.isNaN(d.getTime())) return null;
  const diff = diffYearsMonthsDays(d, now);
  return diff.years + diff.months / 12 + diff.days / 365.25;
}

function formatServiceLengthShort(fromIso: string | null, now = new Date()) {
  if (!fromIso) return "—";
  const d = new Date(fromIso);
  if (Number.isNaN(d.getTime())) return "—";
  const diff = diffYearsMonthsDays(d, now);
  return `${diff.years}y ${diff.months}m ${diff.days}d`;
}

function ymd(d: string | null) {
  if (!d) return null;
  const dt = new Date(d);
  if (Number.isNaN(dt.getTime())) return null;
  return dt.toISOString().slice(0, 10);
}

function daysUntil(dateYmd: string | null) {
  if (!dateYmd) return null;
  const today = new Date();
  const t = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  const dt = new Date(dateYmd);
  if (Number.isNaN(dt.getTime())) return null;
  const diff = dt.getTime() - t.getTime();
  return Math.ceil(diff / (24 * 60 * 60 * 1000));
}

function nextLicenseExpiryFromLicensureRow(r: LicensureRow | null) {
  if (!r) return { ymd: null as string | null, days: null as number | null };
  const cands = [ymd(r.driver_expiration), ymd(r.security_expiration), ymd(r.insurance_expiration)].filter(Boolean) as string[];
  if (!cands.length) return { ymd: null, days: null };
  const sorted = [...cands].sort((a, b) => a.localeCompare(b));
  const next = sorted[0];
  return { ymd: next, days: daysUntil(next) };
}

function downloadBlob(filename: string, blob: Blob) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

function weekOfMonth(date: Date) {
  const day = date.getDate();
  return Math.floor((day - 1) / 7) + 1;
}

export default function ReassignPage() {
  const router = useRouter();
  const { role: sessionRole } = useAuthRole();

  const [viewMode, setViewMode] = useState<"grid" | "table">(() => {
    if (typeof window !== "undefined") {
      return (localStorage.getItem("reassign:viewMode") as "grid" | "table") || "grid";
    }
    return "grid";
  });

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>("");
  const [employees, setEmployees] = useState<Applicant[]>([]);
  const [licensureByApplicantId, setLicensureByApplicantId] = useState<
    Record<string, { nextYmd: string | null; nextDays: number | null }>
  >({});
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState<"name" | "last_name" | "letter" | "created_at" | "category" | "service">("name");

  const [filtersOpen, setFiltersOpen] = useState(false);
  const [genderFilter, setGenderFilter] = useState<string>("ALL");
  const [detachmentFilter, setDetachmentFilter] = useState<string>("ALL");
  const [positionFilter, setPositionFilter] = useState<string>("ALL");
  const [hasPhotoFilter, setHasPhotoFilter] = useState<"ALL" | "YES" | "NO">("ALL");
  const [hiredMonthFilter, setHiredMonthFilter] = useState("ALL"); // MM
  const [yearsServiceFilter, setYearsServiceFilter] = useState<"ALL" | "<1" | "1-5" | ">5">("ALL");

  const [editorOpen, setEditorOpen] = useState(false);
  const [editorApplicantId, setEditorApplicantId] = useState<string | null>(null);

  const [exportOpen, setExportOpen] = useState(false);
  const [exportMonth, setExportMonth] = useState("ALL"); // MM
  const [exportWeek, setExportWeek] = useState("ALL"); // 1..5
  const [exportTitle, setExportTitle] = useState("Reassign (1+ year of service)");

  async function fetchEmployees() {
    setLoading(true);
    setError("");
    try {
      const { data, error: fetchError } = await supabase
        .from("applicants")
        .select(
          "applicant_id, created_at, date_hired_fsai, first_name, middle_name, last_name, client_position, detachment, status, gender, birth_date, age, client_contact_num, client_email, profile_image_path, is_archived, is_trashed"
        )
        .eq("is_archived", false)
        .eq("is_trashed", false)
        .order("created_at", { ascending: false })
        .limit(500);

      if (fetchError) {
        console.error(fetchError);
        setError(fetchError.message || "Failed to load Reassign list");
        setEmployees([]);
        setLicensureByApplicantId({});
      } else {
        const list = (data as Applicant[]) || [];
        setEmployees(list);

        try {
          const ids = list.map((x) => x.applicant_id).filter(Boolean);
          if (!ids.length) {
            setLicensureByApplicantId({});
          } else {
            const map: Record<string, { nextYmd: string | null; nextDays: number | null }> = {};
            const chunkSize = 500;
            for (let i = 0; i < ids.length; i += chunkSize) {
              const chunk = ids.slice(i, i + chunkSize);
              const licRes = await supabase
                .from("licensure")
                .select("applicant_id, driver_expiration, security_expiration, insurance_expiration")
                .in("applicant_id", chunk);
              if (licRes.error) break;
              for (const r of (licRes.data as LicensureRow[]) || []) {
                const next = nextLicenseExpiryFromLicensureRow(r);
                map[String(r.applicant_id)] = { nextYmd: next.ymd, nextDays: next.days };
              }
            }
            setLicensureByApplicantId(map);
          }
        } catch {
          setLicensureByApplicantId({});
        }
      }
    } finally {
      setLoading(false);
    }
  }

  function getExportCandidates() {
    const now = new Date();
    return filtered
      .filter((e) => {
        const years = serviceYearsExact(e.date_hired_fsai, now);
        if (years == null || years < 1) return false;

        if (exportMonth !== "ALL" || exportWeek !== "ALL") {
          if (!e.date_hired_fsai) return false;
          const hired = new Date(e.date_hired_fsai);
          if (Number.isNaN(hired.getTime())) return false;
          if (exportMonth !== "ALL") {
            const m = String(hired.getMonth() + 1).padStart(2, "0");
            if (m !== exportMonth) return false;
          }
          if (exportWeek !== "ALL") {
            const w = String(weekOfMonth(hired));
            if (w !== exportWeek) return false;
          }
        }

        return true;
      });
  }

  function exportFileBase() {
    const parts = ["reassign", "min1yr"];
    if (exportMonth !== "ALL") parts.push(`m${exportMonth}`);
    if (exportWeek !== "ALL") parts.push(`w${exportWeek}`);
    parts.push(new Date().toISOString().slice(0, 10));
    return parts.join("_");
  }

  function exportEmployeesXlsx() {
    setError("");
    const rows = getExportCandidates();
    if (!rows.length) {
      setError("No employees match the export criteria (must be 1+ year of service).");
      return;
    }
    const title = exportTitle.trim() || "Reassign (1+ year of service)";
    const now = new Date();
    const data = rows.map((e) => ({
      Name: getFullName(e),
      "Job Title": e.client_position ?? "",
      Detachment: e.detachment ?? "",
      Gender: (e.gender ?? "").trim(),
      "Hire Date": e.date_hired_fsai ? new Date(e.date_hired_fsai).toLocaleDateString() : "",
      "Service Length": formatServiceLengthShort(e.date_hired_fsai, now),
      Email: (e.client_email ?? "").trim(),
      Phone: (e.client_contact_num ?? "").trim(),
    }));

    const headers = ["Name", "Job Title", "Detachment", "Gender", "Hire Date", "Service Length", "Email", "Phone"];
    const body = data.map((row) => [
      row.Name,
      row["Job Title"],
      row.Detachment,
      row.Gender,
      row["Hire Date"],
      row["Service Length"],
      row.Email,
      row.Phone,
    ]);
    const ws = XLSX.utils.aoa_to_sheet([
      [title],
      [`Generated: ${new Date().toLocaleString()}`],
      [],
      headers,
      ...body,
    ]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Reassign");
    const out = XLSX.write(wb, { type: "array", bookType: "xlsx" });
    downloadBlob(
      `${exportFileBase()}.xlsx`,
      new Blob([out], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" })
    );
    setExportOpen(false);
  }

  function exportEmployeesPdf() {
    setError("");
    const rows = getExportCandidates();
    if (!rows.length) {
      setError("No employees match the export criteria (must be 1+ year of service).");
      return;
    }
    const title = exportTitle.trim() || "Reassign (1+ year of service)";
    const now = new Date();
    const doc = new jsPDF({ orientation: "landscape", unit: "pt", format: "a4" });
    doc.setFontSize(14);
    doc.text(title, 40, 40);

    const head = [["Name", "Job Title", "Detachment", "Gender", "Hire Date", "Service", "Email", "Phone"]];
    const body = rows.map((e) => [
      getFullName(e),
      e.client_position ?? "",
      e.detachment ?? "",
      (e.gender ?? "").trim(),
      e.date_hired_fsai ? new Date(e.date_hired_fsai).toLocaleDateString() : "",
      formatServiceLengthShort(e.date_hired_fsai, now),
      (e.client_email ?? "").trim(),
      (e.client_contact_num ?? "").trim(),
    ]);

    autoTable(doc, {
      startY: 60,
      head,
      body,
      styles: { fontSize: 8, cellPadding: 3 },
      headStyles: { fillColor: [255, 218, 3], textColor: [0, 0, 0] },
    });

    doc.save(`${exportFileBase()}.pdf`);
    setExportOpen(false);
  }

  useEffect(() => {
    try {
      const saved = window.localStorage.getItem("reassign:viewMode");
      if (saved === "grid" || saved === "table") setViewMode(saved);
    } catch {
      // ignore
    }

    fetchEmployees();

    const channel = supabase
      .channel("realtime:applicants-reassign")
      .on("postgres_changes", { event: "*", schema: "public", table: "applicants" }, () => fetchEmployees())
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  useEffect(() => {
    try {
      window.localStorage.setItem("reassign:viewMode", viewMode);
    } catch {
      // ignore
    }
  }, [viewMode]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();

    let list = employees.filter((e) => normalizeStatus(e.status) === "REASSIGN");

    if (genderFilter !== "ALL") {
      const gf = genderFilter.trim().toUpperCase();
      list = list.filter((e) => (e.gender ?? "").trim().toUpperCase() === gf);
    }

    if (detachmentFilter !== "ALL") {
      list = list.filter((e) => (e.detachment ?? "") === detachmentFilter);
    }

    if (positionFilter !== "ALL") {
      list = list.filter((e) => (e.client_position ?? "") === positionFilter);
    }

    if (hasPhotoFilter !== "ALL") {
      list = list.filter((e) => {
        const has = Boolean((e.profile_image_path ?? "").trim());
        return hasPhotoFilter === "YES" ? has : !has;
      });
    }

    if (hiredMonthFilter !== "ALL") {
      list = list.filter((e) => {
        if (!e.date_hired_fsai) return false;
        const hired = new Date(e.date_hired_fsai);
        if (Number.isNaN(hired.getTime())) return false;
        const month = String(hired.getMonth() + 1).padStart(2, "0");
        return month === hiredMonthFilter;
      });
    }

    if (yearsServiceFilter !== "ALL") {
      list = list.filter((e) => {
        const years = serviceYearsExact(e.date_hired_fsai, new Date());
        if (years == null) return false;
        if (yearsServiceFilter === "<1") return years < 1;
        if (yearsServiceFilter === "1-5") return years >= 1 && years <= 5;
        if (yearsServiceFilter === ">5") return years > 5;
        return true;
      });
    }

    if (q) {
      list = list.filter((e) => {
        const haystack = [
          e.applicant_id,
          shortCode(e.applicant_id),
          getFullName(e),
          e.client_position,
          e.detachment,
          normalizeStatus(e.status),
          e.gender,
          e.client_contact_num,
          e.client_email,
          e.birth_date,
          e.age != null ? String(e.age) : "",
        ]
          .filter(Boolean)
          .join(" ")
          .toLowerCase();
        return haystack.includes(q);
      });
    }

    const sorted = [...list].sort((a, b) => {
      if (sortBy === "last_name") {
        const al = (a.last_name ?? "").trim().toLowerCase();
        const bl = (b.last_name ?? "").trim().toLowerCase();
        const d = al.localeCompare(bl);
        return d !== 0 ? d : getFullName(a).localeCompare(getFullName(b));
      }
      if (sortBy === "letter") {
        const al = (a.last_name ?? "").trim().toLowerCase();
        const bl = (b.last_name ?? "").trim().toLowerCase();
        const ai = al ? al[0] : "~";
        const bi = bl ? bl[0] : "~";
        const d = ai.localeCompare(bi);
        return d !== 0 ? d : getFullName(a).localeCompare(getFullName(b));
      }
      if (sortBy === "created_at") {
        return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
      }
      if (sortBy === "category") {
        const ac = (a.client_position ?? "").toLowerCase();
        const bc = (b.client_position ?? "").toLowerCase();
        const d = ac.localeCompare(bc);
        return d !== 0 ? d : getFullName(a).localeCompare(getFullName(b));
      }
      if (sortBy === "service") {
        const ay = serviceYearsExact(a.date_hired_fsai, new Date());
        const by = serviceYearsExact(b.date_hired_fsai, new Date());
        const score = (v: number | null) => (v == null ? -1 : v);
        const d = score(by) - score(ay);
        return d !== 0 ? d : getFullName(a).localeCompare(getFullName(b));
      }
      return getFullName(a).localeCompare(getFullName(b));
    });

    return sorted;
  }, [employees, search, sortBy, genderFilter, detachmentFilter, positionFilter, hasPhotoFilter, hiredMonthFilter, yearsServiceFilter]);

  const filterOptions = useMemo(() => {
    const det = new Set<string>();
    const pos = new Set<string>();
    const gen = new Set<string>();
    for (const e of employees) {
      if (e.detachment) det.add(e.detachment);
      if (e.client_position) pos.add(e.client_position);
      if (e.gender) gen.add(e.gender.trim().toUpperCase());
    }
    return {
      detachments: Array.from(det).sort((a, b) => a.localeCompare(b)),
      positions: Array.from(pos).sort((a, b) => a.localeCompare(b)),
      genders: Array.from(gen).sort((a, b) => a.localeCompare(b)),
    };
  }, [employees]);

  function clearFilters() {
    setGenderFilter("ALL");
    setDetachmentFilter("ALL");
    setPositionFilter("ALL");
    setHasPhotoFilter("ALL");
		setHiredMonthFilter("ALL");
		setYearsServiceFilter("ALL");
  }

  function openEdit(employee: Applicant) {
    setEditorApplicantId(employee.applicant_id);
    setEditorOpen(true);
  }

  return (
    <div className="space-y-5">
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3">
        <div className="flex items-center gap-3 text-black">
      <div className="relative w-full md:w-[360px]">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search reassign employees"
          className="bg-white border rounded-full pl-10 pr-4 py-2 shadow-sm w-full"
        />
      </div>
      <button
        type="button"
        onClick={() => setFiltersOpen(true)}
        className="h-10 w-10 rounded-xl border bg-white flex items-center justify-center"
        aria-label="Filters"
      >
        <SlidersHorizontal className="w-5 h-5 text-gray-700" />
      </button>
        </div>

        <div className="flex items-center gap-3 justify-between md:justify-end">
          <div className="flex items-center gap-2">
            <div className="text-xs text-gray-500">Sort By:</div>
			<select
				value={sortBy}
        onChange={(e) => setSortBy(e.target.value as "name" | "last_name" | "letter" | "created_at" | "category" | "service")}
				className="px-4 py-2 rounded-full bg-white text-black font-medium border border-gray-300"
			>
				<option value="name">Name</option>
        <option value="last_name">Last Name</option>
        <option value="letter">Letter (A-Z)</option>
				<option value="created_at">Newest Date</option>
				<option value="category">Category</option>
				<option value="service">Years of Service</option>
			</select>
          </div>

          <div className="flex items-center gap-2 ml-2">
            <button
              onClick={() => setViewMode("grid")}
              className={`h-10 w-10 rounded-xl border flex items-center justify-center ${
                viewMode === "grid" ? "bg-[#FFDA03]" : "bg-white"
              }`}
              aria-label="Grid view"
              type="button"
            >
              <LayoutGrid className="w-5 h-5 text-black" />
            </button>
            <button
              onClick={() => setViewMode("table")}
              className={`h-10 w-10 rounded-xl border flex items-center justify-center ${
                viewMode === "table" ? "bg-[#FFDA03]" : "bg-white"
              }`}
              aria-label="Table view"
              type="button"
            >
              <Table className="w-5 h-5 text-black" />
            </button>
          </div>

      {sessionRole !== "employee" ? (
        <button
          type="button"
          onClick={() => setExportOpen(true)}
          className="h-10 w-10 rounded-xl border bg-white flex items-center justify-center"
          aria-label="Export"
          title="Export"
        >
          <FileDown className="w-5 h-5 text-gray-800" />
        </button>
      ) : null}
        </div>
      </div>

      {error ? <div className="text-red-600 text-sm">{error}</div> : null}

      {loading ? (
        <div className="glass-panel animate-slide-up rounded-2xl p-8">
          <LoadingCircle label="Loading employees..." />
        </div>
      ) : filtered.length === 0 ? (
        <div className="glass-panel animate-slide-up rounded-2xl p-8 text-center text-gray-500">No employees in Reassign.</div>
      ) : viewMode === "table" ? (
    <div className="relative overflow-x-auto rounded-2xl glass-panel animate-slide-up">
      <table className="w-full text-sm text-black border-separate border-spacing-y-2">
        <thead className="sticky top-0 z-10">
          <tr className="bg-[#FFDA03]">
            <th className="px-4 py-3 text-left font-semibold text-black first:rounded-l-xl">Photo</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Name</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Position</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Gender</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Birth Date</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Age</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Hired Date</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Years w/ Company</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Detachment</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Next License Expiry</th>
            <th className="px-4 py-3 text-left font-semibold text-black">Status</th>
            {sessionRole !== "employee" ? (
              <th className="px-4 py-3 text-center font-semibold text-black last:rounded-r-xl">Actions</th>
            ) : null}
          </tr>
        </thead>
        <tbody>
          {filtered.map((e) => {
            const profileUrl = getProfileUrl(e.profile_image_path);
            const next = licensureByApplicantId[e.applicant_id] || { nextYmd: null, nextDays: null };
            const canClick = sessionRole !== "employee";
            const detailsHref = `/Main_Modules/Employees/details/?id=${encodeURIComponent(
              e.applicant_id
            )}&from=${encodeURIComponent("/Main_Modules/Reassign/")}`;

            return (
              <tr
                key={e.applicant_id}
                role={canClick ? "button" : undefined}
                tabIndex={canClick ? 0 : -1}
                onKeyDown={(ev) => {
                  if (!canClick) return;
                  if (ev.key === "Enter" || ev.key === " ") {
                    ev.preventDefault();
                    router.push(detailsHref);
                  }
                }}
                onClick={() => {
                  if (!canClick) return;
                  router.push(detailsHref);
                }}
                className={`animated-row border-b border-gray-100 transition ${canClick ? "hover:shadow-md cursor-pointer" : ""}`}
