	async function loadPreview() {
		function daysUntilYmd(ymdValue: string) {
			if (!ymdValue) return null;
			const [y, m, d] = ymdValue.split("-").map((n) => Number(n));
			const target = new Date(y, m - 1, d, 0, 0, 0, 0);
			const today = new Date();
			const t0 = new Date(today.getFullYear(), today.getMonth(), today.getDate(), 0, 0, 0, 0);
			return Math.round((target.getTime() - t0.getTime()) / (24 * 60 * 60 * 1000));
		}

		async function loadOtherPreviewRows(daysBeforeExpiry: number, allowExpired: boolean, expiredWindow: number) {
			const out: ExpiringRow[] = [];
			const res = await supabase
				.from("other_expiration_items")
				.select("id, item_name, expiration_type, expires_on, days_before_expiry, recipient_email, is_active")
				.eq("is_active", true)
				.limit(300);

			let rows: Array<{ id: number; item_name: string; expiration_type: string; expires_on: string; days_before_expiry?: number | null; recipient_email: string | null }> = [];
			if (res.error) {
				const msg = safeText((res.error as any)?.message || res.error);
				if (!/days_before_expiry/i.test(msg)) throw res.error;
				const fallback = await supabase
					.from("other_expiration_items")
					.select("id, item_name, expiration_type, expires_on, recipient_email, is_active")
					.eq("is_active", true)
					.limit(300);
				if (fallback.error) throw fallback.error;
				rows = ((fallback.data as Array<{ id: number; item_name: string; expiration_type: string; expires_on: string; recipient_email: string | null }>) ?? []).map((row) => ({
					...row,
					days_before_expiry: null,
				}));
			} else {
				rows = (res.data as Array<{ id: number; item_name: string; expiration_type: string; expires_on: string; days_before_expiry?: number | null; recipient_email: string | null }>) ?? [];
			}

			for (const row of rows) {
				const exp = safeText(row.expires_on);
				const du = daysUntilYmd(exp);
				const perItemDaysBefore = Math.max(
					1,
					Math.min(365, Number(row.days_before_expiry ?? daysBeforeExpiry) || daysBeforeExpiry)
				);
				if (
					exp &&
					du !== null &&
					((du >= 0 && du <= perItemDaysBefore) || (allowExpired && du < 0 && Math.abs(du) <= expiredWindow))
				) {
					out.push({
						applicant_id: `other:${row.id}`,
						last_name: null,
						first_name: row.item_name,
						middle_name: null,
						client_email: row.recipient_email,
						client_contact_num: null,
						expires_on: exp,
						license_type: row.expiration_type,
						days_until_expiry: du,
					});
				}
			}

			return out;
		}

		setPreviewLoading(true);
		setError("");
		try {
			const daysBeforeExpiry = Number(daysBeforeNum);
			if (!Number.isFinite(daysBeforeExpiry)) throw new Error("Days before expiry must be a number.");
			const allowExpired = Boolean(includeExpired);
			const expiredWindow = Math.max(1, Math.min(365, Number(expiredWithinDays || 7)));
			const otherRows = await loadOtherPreviewRows(daysBeforeExpiry, allowExpired, expiredWindow);

			if (electronAPI?.notifications?.previewExpiring) {
				const r = await electronAPI.notifications.previewExpiring({ limit: 25 });
				const merged = [
					...((r?.rows as ExpiringRow[]) ?? []),
					...otherRows,
				].sort((a, b) => a.days_until_expiry - b.days_until_expiry);
				setPreview(merged.slice(0, 25));
				return;
			}

			// Web fallback (compute from base tables; avoids needing v_expiring_licensures view)
			const lic = await supabase
				.from("licensure")
				.select("applicant_id, driver_expiration, security_expiration, insurance_expiration")
				.limit(10000);
			if (lic.error) throw lic.error;

			const licRows = ((lic.data as unknown) as LicensureJoinRow[]) ?? [];
			const ids = Array.from(new Set(licRows.map((r) => r.applicant_id).filter(Boolean)));

			const applicantsById = new Map<string, ApplicantMiniRow>();
			const chunkSize = 500;
			for (let i = 0; i < ids.length; i += chunkSize) {
				const chunk = ids.slice(i, i + chunkSize);
				const aRes = await supabase
					.from("applicants")
						.select("applicant_id, first_name, middle_name, last_name, client_email, client_contact_num")
					.in("applicant_id", chunk);
				if (aRes.error) throw aRes.error;
				for (const a of ((aRes.data as unknown) as ApplicantMiniRow[]) ?? []) {
					applicantsById.set(a.applicant_id, a);
				}
			}


			const include = {
				driver: Boolean(includeDriver),
				security: Boolean(includeSecurity),
				insurance: Boolean(includeInsurance),
			};

			function toYmd(v: unknown) {
				const s = safeText(v);
				if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
				return "";
			}

			const out: ExpiringRow[] = [];
			for (const row of licRows) {
				const a = applicantsById.get(row.applicant_id);
				const base = {
					applicant_id: String(row.applicant_id),
					last_name: a?.last_name ?? null,
					first_name: a?.first_name ?? null,
					middle_name: a?.middle_name ?? null,
					client_email: a?.client_email ?? null,
					client_contact_num: a?.client_contact_num ?? null,
				};

				if (include.driver) {
					const exp = toYmd(row.driver_expiration);
					const du = exp ? daysUntilYmd(exp) : null;
					if (
						exp &&
						du !== null &&
						((du >= 0 && du <= daysBeforeExpiry) || (allowExpired && du < 0 && Math.abs(du) <= expiredWindow))
					) {
						out.push({ ...base, expires_on: exp, license_type: "DRIVER_LICENSE", days_until_expiry: du });
					}
				}
				if (include.security) {
					const exp = toYmd(row.security_expiration);
					const du = exp ? daysUntilYmd(exp) : null;
					if (
						exp &&
						du !== null &&
						((du >= 0 && du <= daysBeforeExpiry) || (allowExpired && du < 0 && Math.abs(du) <= expiredWindow))
					) {
						out.push({ ...base, expires_on: exp, license_type: "SECURITY_LICENSE", days_until_expiry: du });
					}
				}
				if (include.insurance) {
					const exp = toYmd(row.insurance_expiration);
					const du = exp ? daysUntilYmd(exp) : null;
					if (
						exp &&
						du !== null &&
						((du >= 0 && du <= daysBeforeExpiry) || (allowExpired && du < 0 && Math.abs(du) <= expiredWindow))
					) {
						out.push({ ...base, expires_on: exp, license_type: "INSURANCE", days_until_expiry: du });
					}
				}
			}

			const merged = [...out, ...otherRows].sort((a, b) => a.days_until_expiry - b.days_until_expiry);
			setPreview(merged.slice(0, 25));
		} catch (e: unknown) {
			setError(errorMessage(e));
		} finally {
			setPreviewLoading(false);
		}
	}

	async function saveAll() {
		setSaving(true);
		setError("");
		setSuccess("");

		try {
			const cleanGmailUser = safeText(gmailUser);
			if (storeAppPassword && dbHasStoredPassword && !safeText(gmailAppPassword) && !loadedStoredPassword) {
				throw new Error(
					"A stored app password exists in the database. Load it (enable the checkbox) or paste a new app password before saving to avoid clearing it."
				);
			}
			const templateNotes = buildTemplateNotes(emailSubject, emailBodyHtml);
			const daysBeforeValue = Number(daysBeforeNum);
			if (!cleanGmailUser) {
				throw new Error("Gmail User is required.");
			}
			if (!Number.isFinite(daysBeforeValue) || daysBeforeValue < 1 || daysBeforeValue > 365) {
				throw new Error("Days before expiry must be between 1 and 365.");
			}

			if (electronAPI?.settings?.saveNotificationConfig) {
				const session = await supabase.auth.getSession();
				const actor = {
					user_id: session.data.session?.user?.id ?? null,
					email: session.data.session?.user?.email ?? null,
				};
				await electronAPI.settings.saveNotificationConfig({
					email: {
						gmail_user: cleanGmailUser,
						is_active: Boolean(isActive),
						notes: templateNotes,
						gmail_app_password: safeText(gmailAppPassword) || null,
					},
					preferences: {
						is_enabled: Boolean(enabled),
							send_to_employees: Boolean(sendToEmployees),
						days_before_expiry: daysBeforeValue,
						include_driver_license: Boolean(includeDriver),
						include_security_license: Boolean(includeSecurity),
						include_insurance: Boolean(includeInsurance),
						use_scheduled_send: Boolean(useScheduledSend),
						send_time_local: safeText(sendTimeLocal) || "08:00",
						timezone: safeText(timezone) || "Asia/Manila",
					},
					storeAppPassword: Boolean(storeAppPassword),
					actor,
				});

				if (electronAPI?.settings?.saveLocalNotificationPrefs) {
					await electronAPI.settings.saveLocalNotificationPrefs({
						includeExpired: Boolean(includeExpired),
						expiredWithinDays: Math.max(1, Math.min(365, Number(expiredWithinDays || 7))),
						sendToEmployees: Boolean(sendToEmployees),
					});
				}
			} else {
				// Web fallback (anon key) – saving sender credentials is desktop-only.
				const existingPref = await supabase
					.from("notification_preferences")
					.select("id")
					.limit(1)
					.maybeSingle();
				if (existingPref.error) throw existingPref.error;

				if (existingPref.data?.id) {
					const upd = await supabase
						.from("notification_preferences")
						.update({
							is_enabled: Boolean(enabled),
								send_to_employees: Boolean(sendToEmployees),
							days_before_expiry: daysBeforeValue,
							include_driver_license: Boolean(includeDriver),
							include_security_license: Boolean(includeSecurity),
							include_insurance: Boolean(includeInsurance),
							use_scheduled_send: Boolean(useScheduledSend),
							send_time_local: safeText(sendTimeLocal) || "08:00",
							timezone: safeText(timezone) || "Asia/Manila",
						})
						.eq("id", existingPref.data.id);
					if (upd.error) throw upd.error;
				} else {
					const ins = await supabase.from("notification_preferences").insert({
						is_enabled: Boolean(enabled),
							send_to_employees: Boolean(sendToEmployees),
						days_before_expiry: daysBeforeValue,
						include_driver_license: Boolean(includeDriver),
						include_security_license: Boolean(includeSecurity),
						include_insurance: Boolean(includeInsurance),
						use_scheduled_send: Boolean(useScheduledSend),
						send_time_local: safeText(sendTimeLocal) || "08:00",
						timezone: safeText(timezone) || "Asia/Manila",
					});
					if (ins.error) throw ins.error;
				}
			}

			if (storeAppPassword) {
				setDbHasStoredPassword(Boolean(safeText(gmailAppPassword)));
			}

			// Reload what was actually saved (ensures the UI reflects DB immediately)
			if (electronAPI?.settings?.loadNotificationConfig) {
				try {
					const cfg = await electronAPI.settings.loadNotificationConfig();
					applyLoadedConfig(cfg);
					if ((cfg as { unavailable?: boolean; error?: string } | null)?.unavailable) {
						setError(
							safeText((cfg as { error?: string } | null)?.error) ||
							"Supabase is temporarily unreachable. Saved values may not be fully reloaded yet."
						);
					}
				} catch {
					// ignore reload errors
				}
			}

			// Refresh preview and logs immediately.
			void loadPreview();
			void refreshLogs();

			// Do NOT auto-send on Save; sending remains a manual action via "Run now".
			setSuccess("Saved notification settings.");
		} catch (e: unknown) {
			setError(errorMessage(e));
		} finally {
			setSaving(false);
		}
	}

	return (
		<section className="glass-panel animate-slide-up rounded-2xl shadow-2xl p-5 space-y-6 border-none">
			<div className="flex items-center justify-between gap-3 mb-4">
				<div>
					<div className="text-lg font-semibold text-black">Settings</div>
					<div className="text-sm text-gray-500">Email notifications for expiring licensures</div>
				</div>
				<div className="flex items-center gap-2">
					{canAdminExport ? (
						<button
							onClick={async () => {
								setExporting(true);
								setError("");
								setSuccess("");
								try {
									if (!electronAPI?.admin?.exportDatabaseExcel) {
										throw new Error("Export is only available in the Electron desktop app.");
									}
									const res = await electronAPI.admin.exportDatabaseExcel();
									if (res?.cancelled) {
										setSuccess("Export cancelled.");
										return;
									}
									if (!res?.ok || !res?.filePath) {
										throw new Error("Export failed.");
									}
									const skipped = Array.isArray(res.skippedTables) ? res.skippedTables.length : 0;
									setSuccess(
										`Exported to: ${res.filePath}${skipped ? ` (skipped ${skipped} missing tables)` : ""}`
									);
								} catch (e: unknown) {
									setError(errorMessage(e));
								} finally {
									setExporting(false);
								}
						}}
							disabled={exporting || !isDesktop}
							className="animated-btn px-4 py-2 rounded-xl bg-[#FFDA03] text-black font-medium disabled:opacity-50 hover:brightness-95"
						>
							{exporting ? "Exporting…" : "Export database"}
						</button>
					) : null}
					<button
						onClick={() => router.push("/Main_Modules/Dashboard/")}
						className="animated-btn px-4 py-2 rounded-xl bg-white border hover:bg-white"
					>
						Back
					</button>
				</div>
			</div>

			<div className="flex flex-wrap items-center gap-2">
				<div className="inline-flex items-center gap-2 rounded-xl border px-3 py-2 text-sm">
					<span className="text-gray-600">Notifications:</span>
					<span className={enabled ? "text-green-700 font-semibold" : "text-gray-600 font-semibold"}>
						{enabled ? "Enabled" : "Disabled"}
					</span>
				</div>
				<div className="inline-flex items-center gap-2 rounded-xl border px-3 py-2 text-sm">
					<span className="text-gray-600">Log:</span>
					<select
						value={logStatus}
						onChange={(e) => setLogStatus(e.target.value)}
						className="rounded-lg border px-2 py-1 text-black bg-white"
					>
						<option value="ALL" className="text-black">All</option>
						<option value="SENT" className="text-black">Sent</option>
						<option value="FAILED" className="text-black">Failed</option>
						<option value="SKIPPED" className="text-black">Skipped</option>
						<option value="QUEUED" className="text-black">Queued</option>
					</select>
				</div>
				{!hydrated ? (
					<div className="text-xs text-gray-500">Checking desktop integration...</div>
				) : isDesktop ? (
					<div className="text-xs text-gray-500">
						Gmail user in env: {envHasGmailUser ? "yes" : envHasGmailUser === false ? "no" : "unknown"} • Gmail pass in env:{" "}
						{envHasGmailPass ? "yes" : envHasGmailPass === false ? "no" : "unknown"}
					</div>
				) : (
					<div className="text-xs text-gray-500">
						Desktop email sending is only available in the Electron app.
					</div>
				)}
			</div>

			{loading ? (
				<div className="glass-panel rounded-2xl border-none p-8">
					<LoadingCircle label="Loading settings..." />
				</div>
			) : (
				<div className="space-y-6">
					{error ? (
						<div className="rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
							{error}
						</div>
					) : null}
					{success ? (
						<div className="rounded-xl border border-green-200 bg-green-50 px-4 py-3 text-sm text-green-700">
							{success}
						</div>
					) : null}

					<div className="glass-panel animate-scale-in rounded-2xl border-none p-4">
						<div className="flex flex-wrap items-start justify-between gap-3 mb-3">
							<div>
								<div className="font-semibold text-black">My profile</div>
								<div className="text-xs text-gray-500">
									Shown in top navigation. Images are stored in bucket <span className="font-mono">{PROFILE_BUCKET}</span>.
								</div>
							</div>
							<div className="text-xs text-gray-500">Account: {profileUsername || "-"}</div>
						</div>

						{profileAdminId ? (
							<div className="grid grid-cols-1 md:grid-cols-[auto,1fr] gap-4 items-start">
								<div className="h-24 w-24 rounded-2xl overflow-hidden border bg-gray-100 flex items-center justify-center shrink-0">
									{profileImageUrl ? (
										<div
											role="img"
											aria-label={profileDisplayLabel}
											className="h-full w-full bg-cover bg-center"
											style={{ backgroundImage: `url("${profileImageUrl}")` }}
										/>
									) : (
										<span className="text-xl font-semibold text-gray-500">{profileBadgeLabel}</span>
									)}
								</div>

								<div className="space-y-3 min-w-0">
									<div>
										<label className="block text-sm mb-1 text-black">Display name</label>
										<input
											value={profileDisplayName}
											onChange={(e) => setProfileDisplayName(e.target.value)}
											placeholder="Enter your display name"
											className="w-full rounded-xl border px-3 py-2 text-black"
										/>
									</div>

									<div className="text-xs text-gray-500 break-all">
										Current image path: {profileImagePath || "Not uploaded"}
									</div>

									<div className="flex flex-wrap items-center gap-2">
										<button
											type="button"
											onClick={() => void saveProfileName()}
											disabled={profileSaving || profileUploading || profileRemoving}
											className="animated-btn px-4 py-2 rounded-xl bg-black text-white disabled:opacity-50 hover:bg-gray-800"
										>
											{profileSaving ? "Saving..." : "Save name"}
										</button>

										<button
											type="button"
											onClick={() => profileFileInputRef.current?.click()}
											disabled={profileUploading || profileSaving || profileRemoving}
											className="animated-btn px-4 py-2 rounded-xl bg-[#FFDA03] text-black font-medium disabled:opacity-50 hover:brightness-95"
										>
											{profileUploading ? "Uploading..." : "Upload image"}
										</button>

										{profileImagePath ? (
											<button
												type="button"
												onClick={() => void removeProfileImage()}
												disabled={profileRemoving || profileUploading || profileSaving}
												className="animated-btn px-4 py-2 rounded-xl bg-white border text-black disabled:opacity-50 hover:bg-white"
											>
												{profileRemoving ? "Removing..." : "Remove image"}
											</button>
										) : null}
									</div>

									<div className="text-xs text-gray-500">Accepted image files up to 5MB.</div>
								</div>
							</div>
						) : (
							<div className="rounded-xl border border-yellow-200 bg-yellow-50 px-3 py-2 text-sm text-yellow-800">
								No active admin session found. Sign in again to edit your profile.
							</div>
						)}

						<input
							ref={profileFileInputRef}
							type="file"
							accept="image/*"
							className="hidden"
							onChange={(e) => {
								const file = e.target.files?.[0] ?? null;
								e.currentTarget.value = "";
								void uploadProfileImage(file);
							}}
						/>
					</div>

					<div className="grid grid-cols-1 lg:grid-cols-2 gap-4 items-start">
						<div className="glass-panel animate-scale-in rounded-2xl border-none p-4">
							<div className="font-semibold mb-2 text-black">Gmail Sender</div>
							<div className="text-xs text-gray-500 mb-4">
								Used to send notification emails. This app uses Gmail App Password auth only.
								The sender address is read from <span className="font-mono">GMAIL_USER</span> in <span className="font-mono">.env.local</span>.
							</div>

							{isDesktop ? (
								<div className="rounded-xl border border-gray-200 bg-white px-3 py-2 text-sm text-gray-700 mb-3">
									<div className="flex flex-wrap items-center gap-2">
										<span className="font-semibold">Sender priority:</span>
										<span className="font-mono">GMAIL_USER</span>
										<span className="text-gray-500">(env)</span>
										<span className="text-gray-500">→</span>
										<span>this saved Gmail User</span>
										<span className="text-gray-500">(Settings)</span>
										<span className="text-gray-500">•</span>
										<span>Env app password: {envHasGmailPass ? "yes" : envHasGmailPass === false ? "no" : "unknown"}</span>
										<span className="text-gray-500">•</span>
										<span>Stored app password in DB: {dbHasStoredPassword ? "yes" : "no"}</span>
									</div>
									<div className="mt-2 flex flex-wrap gap-2">
										<button
											onClick={async () => {
												setError("");
												setSuccess("");
												try {
													if (!electronAPI?.settings?.clearStoredGmailAppPassword) {
														throw new Error("This action is only available in the Electron desktop app.");
													}
													await electronAPI.settings.clearStoredGmailAppPassword();
													setDbHasStoredPassword(false);
													setDbStoredPasswordCache("");
													setGmailAppPassword("");
													setLoadedStoredPassword(false);
													setSuccess("Stored Gmail App Password cleared from database.");
												} catch (e: unknown) {
													setError(errorMessage(e));
												}
										}}
										disabled={!dbHasStoredPassword}
										className="animated-btn px-3 py-2 rounded-xl bg-white border disabled:opacity-50 text-black hover:bg-white"
									>
										Clear stored app password
									</button>
									<button
											onClick={async () => {
												setError("");
												setSuccess("");
												try {
													if (!electronAPI?.settings?.removeGmailSender) {
														throw new Error("This action is only available in the Electron desktop app.");
													}
												const ok = window.confirm(
													"Remove the Gmail sender settings? This cannot be undone."
												);
												if (!ok) return;
													await electronAPI.settings.removeGmailSender();
													setGmailUser("");
													setEmailSubject("");
													setEmailBodyHtml("");
													setIsActive(true);
													setDbHasStoredPassword(false);
													setDbStoredPasswordCache("");
													setLoadedStoredPassword(false);
													setSuccess("Gmail sender settings removed.");
												} catch (e: unknown) {
													setError(errorMessage(e));
												}
										}}
										className="animated-btn px-3 py-2 rounded-xl bg-red-600 text-white hover:bg-red-700"
									>
										Remove sender
									</button>
								</div>
							</div>
						) : null}

							<label className="block text-sm mb-1 text-black">Gmail User</label>
							<input
								value={gmailUser}
								onChange={(e) => setGmailUser(e.target.value)}
								placeholder="yourcompany.notifications@gmail.com"
								className="w-full rounded-xl border px-3 py-2 text-black"
							/>

							<div className="flex items-center gap-2 mt-3">
								<input
									id="isActive"
									type="checkbox"
									checked={isActive}
									onChange={(e) => setIsActive(e.target.checked)}
								/>
								<label htmlFor="isActive" className="text-sm text-black">
									Active
								</label>
							</div>

							<div className="flex items-center gap-2 mt-3">
								<input
									id="storePass"
									type="checkbox"
									checked={storeAppPassword}
									onChange={async (e) => {
									const next = e.target.checked;
									setStoreAppPassword(next);
									setError("");
									setSuccess("");

									if (!next) {
										setGmailAppPassword("");
										setLoadedStoredPassword(false);
										return;
									}

									// If DB already has one, auto-load it (we already received it via loadNotificationConfig).
									if (!dbHasStoredPassword) return;
									if (safeText(dbStoredPasswordCache)) {
										setGmailAppPassword(dbStoredPasswordCache);
										setLoadedStoredPassword(true);
										return;
									}

									// Fallback for older/partial configs: try fetching via IPC if available.
									if (!electronAPI?.settings?.getStoredGmailAppPassword) return;
									try {
										const res = await electronAPI.settings.getStoredGmailAppPassword();
										setGmailAppPassword(res?.password ?? "");
										setLoadedStoredPassword(true);
									} catch (err: unknown) {
										setError(errorMessage(err));
										setStoreAppPassword(false);
										setLoadedStoredPassword(false);
									}
								}}
								/>
								<label htmlFor="storePass" className="text-sm text-black">
									Store Gmail App Password in database (not recommended)
								</label>
							</div>

							{storeAppPassword ? (
								<div className="mt-3">
									<label className="block text-sm mb-1 text-black">Gmail App Password</label>
									<input
										type={showAppPassword ? "text" : "password"}
										value={gmailAppPassword}
										onChange={(e) => {
											setLoadedStoredPassword(false);
											setGmailAppPassword(e.target.value);
										}}
										placeholder="xxxx xxxx xxxx xxxx"
										className="w-full rounded-xl border px-3 py-2 text-black"
									/>
									<label className="mt-2 inline-flex items-center gap-2 text-xs text-gray-700">
										<input
											type="checkbox"
											checked={showAppPassword}
											onChange={(e) => setShowAppPassword(e.target.checked)}
										/>
										Show app password
									</label>
									<div className="text-xs text-gray-500 mt-1">
										If a stored password exists, it will auto-fill when you enable the checkbox.
									</div>
								</div>
							) : null}

							<label className="block text-sm mt-4 mb-1 text-black">Email Subject</label>
							<input
								value={emailSubject}
								onChange={(e) => setEmailSubject(e.target.value)}
								placeholder="NOTICE: LICENSE EXPIRATION ALERT ({count})"
								className="w-full rounded-xl border px-3 py-2 text-black"
							/>
							<div className="text-xs text-gray-500 mt-1">
								Tip: use <span className="font-mono">{'{count}'}</span> to insert number of expiring items.
							</div>

							<label className="block text-sm mt-4 mb-1 text-black">Email Body</label>
							<RichTextEditor value={emailBodyHtml} onChange={setEmailBodyHtml} />
							<div className="text-xs text-gray-500 mt-1">
								This content appears above the expiring licenses table.
							</div>
						</div>

						<div className="glass-panel animate-scale-in rounded-2xl border-none p-4">
							<div className="font-semibold mb-2 text-black">Expiring Licensure Preferences</div>

							<div className="flex items-center gap-2 text-black">
								<input
									id="enabled"
									type="checkbox"
									checked={enabled}
									onChange={(e) => setEnabled(e.target.checked)}
								/>
								<label htmlFor="enabled" className="text-sm text-black">
									Enable notifications
								</label>
							</div>

							<div className="mt-3 rounded-xl border p-3">
								<div className="flex items-center justify-between gap-3">
									<div>
										<div className="text-sm font-semibold text-black">Send Gmail to employees</div>
										<div className="text-xs text-gray-500">Controls sending to employee email addresses (applicants.client_email) and the Expiring Licenses “Resend” button.</div>
									</div>
									<button
										type="button"
										onClick={() => setSendToEmployees((v) => !v)}
										className={`relative inline-flex h-7 w-12 items-center rounded-full border ${sendToEmployees ? "bg-black" : "bg-gray-200"}`}
										aria-label="Toggle send Gmail to employees"
										aria-pressed={sendToEmployees}
									>
										<span
											className={`inline-block h-5 w-5 transform rounded-full bg-white transition ${sendToEmployees ? "translate-x-6" : "translate-x-1"}`}
										/>
									</button>
								</div>

								{!sendToEmployees ? (
									<div className="text-xs text-gray-600 mt-2">
										Employee sending is disabled. Notification Recipients will still receive the expiring list.
									</div>
								) : null}
							</div>

							<label className="block text-sm mt-3 mb-1 text-black">Days before expiry</label>
							<input
								type="text"
								inputMode="numeric"
								pattern="[0-9]*"
								value={daysBeforeInput}
								onChange={(e) => {
									const next = e.target.value;
									if (next === "" || /^\d+$/.test(next)) setDaysBeforeInput(next);
								}}
								onBlur={() => {
									const trimmed = daysBeforeInput.trim();
									if (!trimmed) {
										setDaysBeforeInput("30");
										return;
									}
									const n = Number(trimmed);
									if (!Number.isFinite(n)) {
										setDaysBeforeInput("30");
										return;
									}
									const clamped = Math.min(365, Math.max(1, Math.trunc(n)));
									setDaysBeforeInput(String(clamped));
								}}
								placeholder="30"
								className="w-full rounded-xl border px-3 py-2 text-black"
							/>

							<div className="mt-3 grid grid-cols-1 sm:grid-cols-2 gap-2">
								<label className="flex items-center gap-2 text-sm text-black">
									<input
										type="checkbox"
										checked={includeDriver}
										onChange={(e) => setIncludeDriver(e.target.checked)}
									/>
